import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('MailScene')
export class MailScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Button)
    claimAllBtn: Button = null;
    
    @property(ScrollView)
    mailListScrollView: ScrollView = null;
    
    @property(Node)
    mailItemPrefab: Node = null;
    
    @property(Node)
    mailDetailPanel: Node = null;
    
    @property(Label)
    detailTitleLabel: Label = null;
    
    @property(Label)
    detailContentLabel: Label = null;
    
    @property(Label)
    detailRewardLabel: Label = null;
    
    @property(Button)
    detailClaimBtn: Button = null;
    
    private mails = [
        { 
            id: 1, 
            title: '新手礼包', 
            content: '欢迎来到财神大陆！这是给你的新手礼包。', 
            reward: { incense_money: 1000, incense_sticks: 10 },
            isRead: false,
            isClaimed: false,
            time: '2026-03-23 00:00'
        },
        { 
            id: 2, 
            title: '系统维护补偿', 
            content: '由于系统维护，给您带来不便，特此补偿。', 
            reward: { yuanbao: 60 },
            isRead: true,
            isClaimed: false,
            time: '2026-03-22 20:00'
        },
        { 
            id: 3, 
            title: '活动奖励', 
            content: '恭喜您在活动中获得奖励！', 
            reward: { candles: 5 },
            isRead: true,
            isClaimed: true,
            time: '2026-03-22 12:00'
        }
    ];
    
    private selectedMail: any = null;
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.claimAllBtn.node.on(Button.EventType.CLICK, this.onClaimAll, this);
        this.detailClaimBtn.node.on(Button.EventType.CLICK, this.onClaimSelected, this);
    }
    
    start() {
        this.updateMailList();
        this.mailDetailPanel.active = false;
    }
    
    updateMailList() {
        const content = this.mailListScrollView.content;
        content.removeAllChildren();
        
        for (const mail of this.mails) {
            const item = instantiate(this.mailItemPrefab);
            
            item.getChildByName('TitleLabel').getComponent(Label).string = 
                (mail.isRead ? '' : '🔴 ') + mail.title;
            item.getChildByName('TimeLabel').getComponent(Label).string = mail.time;
            item.getChildByName('StatusLabel').getComponent(Label).string = 
                mail.isClaimed ? '已领取' : '未领取';
            
            const btn = item.getComponent(Button);
            btn.node.on(Button.EventType.CLICK, () => this.onMailClick(mail), this);
            
            content.addChild(item);
        }
    }
    
    onMailClick(mail: any) {
        this.selectedMail = mail;
        mail.isRead = true;
        
        this.detailTitleLabel.string = mail.title;
        this.detailContentLabel.string = mail.content;
        
        let rewardText = '';
        for (const [key, value] of Object.entries(mail.reward)) {
            rewardText += `${key}: ${value} `;
        }
        this.detailRewardLabel.string = rewardText || '无附件';
        
        this.detailClaimBtn.node.active = !mail.isClaimed;
        this.mailDetailPanel.active = true;
        
        this.updateMailList();
    }
    
    onClaimSelected() {
        if (!this.selectedMail || this.selectedMail.isClaimed) return;
        
        // 发放奖励
        for (const [key, value] of Object.entries(this.selectedMail.reward)) {
            GameManager.getInstance().playerData.addCurrency(key, value as number);
        }
        
        this.selectedMail.isClaimed = true;
        this.detailClaimBtn.node.active = false;
        this.updateMailList();
    }
    
    onClaimAll() {
        for (const mail of this.mails) {
            if (!mail.isClaimed) {
                for (const [key, value] of Object.entries(mail.reward)) {
                    GameManager.getInstance().playerData.addCurrency(key, value as number);
                }
                mail.isClaimed = true;
            }
        }
        this.updateMailList();
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
